import React, { useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import './CompanyPage.css';

// ── BACKEND STATIC SIMULATION DATABASE ──
const BACKEND_COMPANY_DATA = {
  overview: {
    content: "Gv Solutions is a premier technology consulting and custom software development agency based out of Madurai. We architect cutting-edge cloud architectures, cross-platform mobile environments, and automated custom enterprise resource planning (ERP) suites engineered to scale local business digital footprints internationally.",
    media: [
      { type: 'image', url: 'https://images.unsplash.com/photo-1531403009284-440f080d1e12?auto=format&fit=crop&w=600&q=80', alt: 'Workspace Environment' },
      { type: 'image', url: 'https://images.unsplash.com/photo-1522071820081-009f0129c71c?auto=format&fit=crop&w=600&q=80', alt: 'Collaborative Dev Session' }
    ]
  },
  photos: [
    'https://images.unsplash.com/photo-1504384308090-c894fdcc538d?auto=format&fit=crop&w=300&q=80',
    'https://images.unsplash.com/photo-1498050108023-c5249f4df085?auto=format&fit=crop&w=300&q=80',
    'https://images.unsplash.com/photo-1461749280684-dccba630e2f6?auto=format&fit=crop&w=300&q=80',
    'https://images.unsplash.com/photo-1542744094-3a31f103e35f?auto=format&fit=crop&w=300&q=80'
  ],
  catalogue: [
    { id: 'cat-1', title: 'Enterprise Software Spec Brochure', src: 'https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&w=300&q=80', downloadUrl: '#' },
    { id: 'cat-2', title: 'Web Design Portfolio Booklet', src: 'https://images.unsplash.com/photo-1626785774573-4b799315345d?auto=format&fit=crop&w=300&q=80', downloadUrl: '#' }
  ],
  initialReviews: [
    { id: 1, name: "Arun Kumar", pic: "https://images.unsplash.com/photo-1534528741775-53994a69daeb?auto=format&fit=crop&w=100&q=80", rating: 5, comment: "Exceptional architecture design delivery. Built our e-commerce operations layout cleanly ahead of aggressive launch timelines." }
  ],
  products: [
    {
      id: 'prod-101',
      name: 'Custom Cloud Enterprise Resource Planning Premium Suite Pack',
      price: '₹45,000 / Module',
      images: [
        'https://images.unsplash.com/photo-1551434678-e076c223a692?auto=format&fit=crop&w=300&q=80',
        'https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=300&q=80',
        'https://images.unsplash.com/photo-1504868584819-f8e8b4b6d7e3?auto=format&fit=crop&w=300&q=80'
      ]
    },
    {
      id: 'prod-102',
      name: 'E-Commerce Framework Implementation',
      price: '₹25,000 Startup Flat Rate',
      images: [
        'https://images.unsplash.com/photo-1563013544-824ae1d704d3?auto=format&fit=crop&w=300&q=80',
        'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=300&q=80'
      ]
    },
    {
      id: 'prod-103',
      name: 'AI-Driven Predictive Customer Analytics Dashboard Matrix Engine',
      price: '₹80,000 Annual License',
      images: [
        'https://images.unsplash.com/photo-1551288049-bebda4e38f71?auto=format&fit=crop&w=300&q=80',
        'https://images.unsplash.com/photo-1518186285589-2f7649de83e0?auto=format&fit=crop&w=300&q=80',
        'https://images.unsplash.com/photo-1504868584819-f8e8b4b6d7e3?auto=format&fit=crop&w=300&q=80'
      ]
    }
  ],
  sidebar: {
    address: "Surveyor Colony, Madurai, Tamil Nadu - 625007",
    hours: "Mon – Sat: 9:00 AM – 8:00 PM",
    specialisations: "Web Design, Mobile Apps, Enterprise Custom ERP Solutions, Branding Strategy",
    established: "2014",
    relatedCategories: [
      { id: 'rc-1', name: 'Web Designers in Madurai' },
      { id: 'rc-2', name: 'Mobile App Developers' }
    ],
    relatedKeywords: ['Custom ERP', 'SaaS Solutions', 'React Developers', 'Madurai IT Hub']
  }
};

const TABS = ['Overview', 'Photos', 'Catalogue', 'Reviews'];

// ── REUSABLE ISOLATED PRODUCT CARD WIDGET ──
function ProductListingCard({ product, city, company }) {
  const navigate = useNavigate();
  const [currentImgIdx, setCurrentImgIdx] = useState(0);
  const [showFullTitle, setShowFullTitle] = useState(false);

  const maxTitleCharThreshold = 35;
  const isLongTitle = product.name.length > maxTitleCharThreshold;

  const handlePrevImg = (e) => {
    e.stopPropagation();
    setCurrentImgIdx((prev) => (prev === 0 ? product.images.length - 1 : prev - 1));
  };

  const handleNextImg = (e) => {
    e.stopPropagation();
    setCurrentImgIdx((prev) => (prev === product.images.length - 1 ? 0 : prev + 1));
  };

  const handleDotClick = (e, idx) => {
    e.stopPropagation();
    setCurrentImgIdx(idx);
  };

  const handleCardRedirection = () => {
    navigate(`/city/${city}/${company}/product/${product.id}`);
  };

  return (
    <div className="product-listing-card" onClick={handleCardRedirection}>
      <div className="product-card-image-wrapper">
        <img src={product.images[currentImgIdx]} alt={product.name} className="product-card-img" />

        {product.images.length > 1 && (
          <>
            <button type="button" className="card-nav-arrow left" onClick={handlePrevImg}>‹</button>
            <button type="button" className="card-nav-arrow right" onClick={handleNextImg}>›</button>
          </>
        )}

        <div className="product-carousel-dots">
          {product.images.map((_, i) => (
            <span 
              key={i} 
              className={`carousel-dot${i === currentImgIdx ? ' active' : ''}`}
              onClick={(e) => handleDotClick(e, i)}
            />
          ))}
        </div>
      </div>

      <div className="product-card-body-details">
        <div className="product-card-title-frame">
          {showFullTitle || !isLongTitle ? (
            <span className="product-title-text">{product.name}</span>
          ) : (
            <span className="product-title-text">{product.name.slice(0, maxTitleCharThreshold)}...</span>
          )}

          {isLongTitle && (
            <button 
              type="button" 
              className="btn-title-toggle-more" 
              onClick={(e) => { e.stopPropagation(); setShowFullTitle(!showFullTitle); }}
            >
              {showFullTitle ? ' Less' : ' More'}
            </button>
          )}
        </div>
        <div className="product-card-pricing-label">{product.price}</div>
      </div>
    </div>
  );
}

export default function CompanyPage() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('Overview');
  const [reviews, setReviews] = useState(BACKEND_COMPANY_DATA.initialReviews);

  // Login Gate States
  const [userEmail, setUserEmail] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  // Review Entry States
  const [newReviewName, setNewReviewName] = useState('');
  const [newReviewComment, setNewReviewComment] = useState('');
  const [newReviewRating, setNewReviewRating] = useState(5);

  const handleUserLogin = (e) => {
    e.preventDefault();
    if (!userEmail.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) {
      alert('Please enter a valid structure email account routing verification.');
      return;
    }
    setIsLoggedIn(true);
  };

  const handleReviewSubmission = (e) => {
    e.preventDefault();
    if (!newReviewName.trim() || !newReviewComment.trim()) {
      alert('Please compile all criteria elements before submitting input index records.');
      return;
    }

    const compiledReviewObj = {
      id: Date.now(),
      name: newReviewName,
      pic: "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&w=100&q=80",
      rating: parseInt(newReviewRating),
      comment: newReviewComment
    };

    setReviews([compiledReviewObj, ...reviews]);
    setNewReviewName('');
    setNewReviewComment('');
    setNewReviewRating(5);
  };

  const rawAggregateScore = reviews.reduce((acc, curr) => acc + curr.rating, 0);
  const evaluatedAverageRating = reviews.length > 0 ? (rawAggregateScore / reviews.length).toFixed(1) : "5.0";

  return (
    <div className="company-page">
      <div className="container company-layout">
        <div className="row company-layout-row">

          {/* ── LEFT COLUMN SEGMENT: SCROLLABLE MAIN DATA CONTAINER ── */}
          <div className="col-lg-8 company-main-scrollable">

            <div className="profile-card">
              <div className="profile-header">
                <div>
                  <h1 className="profile-name">
                    Gv Solutions
                    <i className="fas fa-check-circle verified-badge-icon"></i>
                  </h1>
                  <div className="profile-rating-row">
                    <span className="profile-rating-badge">{evaluatedAverageRating} ★</span>
                    <span className="profile-rating-text">{reviews.length} Ratings Verified | Claimed Account</span>
                  </div>
                  <div className="profile-location">
                    <i className="fas fa-map-marker-alt"></i> Surveyor Colony, Madurai &nbsp;•&nbsp;
                    <span className="open-status">Open until 8:00 pm</span>
                  </div>
                </div>
              </div>

              <div className="company-actions">
                <a href="tel:08460506156" className="btn-company-call"><i className="fas fa-phone"></i> 08460506156</a>
                <button className="btn-enquire"><i className="far fa-envelope"></i> Enquire Now</button>
                <button className="btn-company-whatsapp"><i className="fab fa-whatsapp"></i> WhatsApp Business</button>
              </div>

              <div className="company-tabs">
                {TABS.map((tab) => (
                  <button key={tab} className={`company-tab${activeTab === tab ? ' active' : ''}`} onClick={() => setActiveTab(tab)}>
                    {tab}
                  </button>
                ))}
              </div>

              <div className="tab-render-window">
                {activeTab === 'Overview' && (
                  <div className="tab-pane-content animation-fade-in">
                    <p className="tab-body-description">{BACKEND_COMPANY_DATA.overview.content}</p>
                    <div className="overview-media-carousel">
                      {BACKEND_COMPANY_DATA.overview.media.map((item, idx) => (
                        <div key={idx} className="overview-carousel-slide"><img src={item.url} alt={item.alt} /></div>
                      ))}
                    </div>
                  </div>
                )}

                {activeTab === 'Photos' && (
                  <div className="tab-pane-content animation-fade-in">
                    <div className="photos-thumbnail-bounded-matrix">
                      {BACKEND_COMPANY_DATA.photos.map((src, idx) => (
                        <div key={idx} className="strict-photo-box-card"><img src={src} alt="Workspace Thumbnail" /></div>
                      ))}
                    </div>
                  </div>
                )}

                {activeTab === 'Catalogue' && (
                  <div className="tab-pane-content animation-fade-in">
                    <div className="catalogue-grid-layout">
                      {BACKEND_COMPANY_DATA.catalogue.map((catItem) => (
                        <div key={catItem.id} className="catalogue-interactive-card">
                          <div className="catalogue-img-frame"><img src={catItem.src} alt={catItem.title} /></div>
                          <div className="catalogue-details-panel">
                            <h6 className="catalogue-item-title">{catItem.title}</h6>
                            <a href={catItem.downloadUrl} className="catalogue-download-action-btn" onClick={(e) => { e.preventDefault(); alert('Downloading PDF...'); }}>
                              <i className="fas fa-arrow-alt-circle-down"></i> Download Brochure PDF
                            </a>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {activeTab === 'Reviews' && (
                  <div className="tab-pane-content animation-fade-in">
                    <div className="reviews-vertical-feed-stack">
                      {reviews.map((rev) => (
                        <div key={rev.id} className="review-row-feed-item">
                          <img className="review-user-avatar" src={rev.pic} alt={rev.name} />
                          <div className="review-feed-meta-box">
                            <div className="review-user-header-line">
                              <span className="review-feed-username">{rev.name}</span>
                              <span className="review-feed-stars-badge">{'★'.repeat(rev.rating)}</span>
                            </div>
                            <p className="review-feed-body-comment">{rev.comment}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>

            {/* PRODUCT SLIDER LISTING MATRIX LAYER SECTION (X-Axis Only Scrollable) */}
            <div className="profile-card">
              <h2 className="section-card-heading">Our Verified Products & Solutions</h2>
              <div className="products-horizontal-scroll-axis-wrapper">
                {BACKEND_COMPANY_DATA.products.map((product) => (
                  <ProductListingCard 
                    key={product.id} 
                    product={product} 
                    city="madurai" 
                    company="gv-solutions" 
                  />
                ))}
              </div>
            </div>

            {/* ESTABLISHMENT TRACK PROFILE */}
            <div className="profile-card">
              <h2 className="section-card-heading">Establishment Track Profile</h2>
              <div className="establishment-details-grid">
                <div className="establishment-grid-node">
                  <span className="establishment-node-label">Year of Corporate Registration</span>
                  <span className="establishment-node-value">{BACKEND_COMPANY_DATA.sidebar.established}</span>
                </div>
                <div className="establishment-grid-node">
                  <span className="establishment-node-label">Current Operational Scale Status</span>
                  <span className="establishment-node-value verified-accent-text">Fully Verified & Compliant</span>
                </div>
              </div>
            </div>

            {/* INTERACTIVE REVIEW WRITING ENGINE CARD WITH EMAIL SIGN-IN LOGIC GATE */}
            <div className="reviews-section">
              <h2 className="section-card-heading">Reviews & Numerical Ratings Summary</h2>

              <div className="review-summary">
                <div className="review-big-score">{evaluatedAverageRating}</div>
                <div>
                  <div className="review-stars">{'★'.repeat(Math.round(parseFloat(evaluatedAverageRating)))}</div>
                  <div className="review-total">Based on verified user records execution tracking</div>
                </div>
              </div>

              {!isLoggedIn ? (
                <div className="review-lockout-login-gate-box">
                  <h4 className="form-contextual-subtitle">Authentication Required</h4>
                  <p className="gate-helper-text">You must verify your identity via email layout parameters before leaving a public review index rating.</p>
                  <form onSubmit={handleUserLogin} className="gate-inline-login-form">
                    <input 
                      type="email" 
                      className="form-text-input-field" 
                      placeholder="Enter your email (e.g. name@domain.com)"
                      required
                      value={userEmail}
                      onChange={(e) => setUserEmail(e.target.value)}
                    />
                    <button type="submit" className="form-submit-review-action-btn">Sign In to Review</button>
                  </form>
                </div>
              ) : (
                <form onSubmit={handleReviewSubmission} className="interactive-review-generation-form animation-fade-in">
                  <div className="authenticated-user-badge-dock">
                    <i className="fas fa-user-lock"></i> Signed in as: <strong>{userEmail}</strong>
                  </div>

                  <div className="form-input-group-row">
                    <div className="form-element-field">
                      <label className="form-input-label">Full Profile Fullname</label>
                      <input 
                        type="text" 
                        className="form-text-input-field" 
                        placeholder="e.g. Ramesh Pandian" 
                        value={newReviewName}
                        onChange={(e) => setNewReviewName(e.target.value)}
                      />
                    </div>

                    <div className="form-element-field">
                      <label className="form-input-label">Allocated Core Rating Scale</label>
                      <select 
                        className="form-select-dropdown-element"
                        value={newReviewRating}
                        onChange={(e) => setNewReviewRating(e.target.value)}
                      >
                        <option value="5">5 Stars (Excellent)</option>
                        <option value="4">4 Stars (Good)</option>
                        <option value="3">3 Stars (Average)</option>
                      </select>
                    </div>
                  </div>

                  <div className="form-element-field full-width-block">
                    <label className="form-input-label">Detailed Experience Review Commentary Text</label>
                    <textarea 
                      rows="3" 
                      className="form-textarea-input-field" 
                      placeholder="Describe project delivery performance..."
                      value={newReviewComment}
                      onChange={(e) => setNewReviewComment(e.target.value)}
                    ></textarea>
                  </div>

                  <button type="submit" className="form-submit-review-action-btn">Publish Review</button>
                </form>
              )}
            </div>

          </div>

          {/* ── RIGHT COLUMN SEGMENT: STICKY SIDEBAR AREA ── */}
          <div className="col-lg-4 company-sidebar-fixed">
            <div className="sidebar-sticky-enclosure-stack">
              <div className="company-sidebar-card">
                <h4 className="company-sidebar-title">Business Information</h4>
                <div className="sidebar-info-row">
                  <i className="fas fa-map-marker-alt sidebar-info-icon"></i>
                  <div>
                    <div className="sidebar-info-label">Address</div>
                    <div className="sidebar-info-value">{BACKEND_COMPANY_DATA.sidebar.address}</div>
                  </div>
                </div>
                <div className="sidebar-info-row">
                  <i className="fas fa-clock sidebar-info-icon"></i>
                  <div>
                    <div className="sidebar-info-label">Working Hours</div>
                    <div className="sidebar-info-value">{BACKEND_COMPANY_DATA.sidebar.hours}</div>
                  </div>
                </div>
              </div>

              <div className="company-sidebar-card">
                <h4 className="company-sidebar-title">Relevant Categories</h4>
                <div className="sidebar-vertical-navigation-links">
                  {BACKEND_COMPANY_DATA.sidebar.relatedCategories.map((cat) => (
                    <div key={cat.id} className="sidebar-navigation-row-link" onClick={() => alert(cat.name)}>
                      <span className="nav-row-text-label">{cat.name}</span>
                      <i className="fas fa-chevron-right nav-row-arrow-indicator"></i>
                    </div>
                  ))}
                </div>
              </div>

              <div className="company-sidebar-card">
                <h4 className="company-sidebar-title">Relevant Keywords</h4>
                <div className="sidebar-keywords-flex-matrix-dock">
                  {BACKEND_COMPANY_DATA.sidebar.relatedKeywords.map((kw, i) => (
                    <span key={i} className="sidebar-keyword-pill-tag-node" onClick={() => alert(kw)}>#{kw}</span>
                  ))}
                </div>
              </div>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}
